\displaystyle{\begin{aligned}
   {\frac{\frac{3r}{r^{2}-36}-1}{\frac{5}{r+6}-\frac{2}{r-6}}}
      \amp = {\frac{\frac{3r}{\left(r+6\right)\mathopen{}\left(r-6\right)}-1}{\frac{5}{r+6}-\frac{2}{r-6}}} \\
      \amp = {\frac{\frac{3r}{\left(r+6\right)\mathopen{}\left(r-6\right)}-1}{\frac{5}{r+6}-\frac{2}{r-6}}} \cdot \frac{{\left(r+6\right)\mathopen{}\left(r-6\right)}}{{\left(r+6\right)\mathopen{}\left(r-6\right)}} \\
      \amp = {\frac{\frac{3r}{\left(r+6\right)\mathopen{}\left(r-6\right)}\mathopen{}\left(r+6\right)\mathopen{}\left(r-6\right)-\left(r+6\right)\mathopen{}\left(r-6\right)}{\frac{5}{r+6}\mathopen{}\left(r+6\right)\mathopen{}\left(r-6\right)-\frac{2}{r-6}\mathopen{}\left(r+6\right)\mathopen{}\left(r-6\right)}} \\
      \amp = {\frac{3r-\left(r^{2}-36\right)}{5\mathopen{}\left(r-6\right)-2\mathopen{}\left(r+6\right)}}, r \ne 6 \text{ and } r \ne -6 \\
